// Deduplicate at the array level — runs ONCE, not per-vendor.
// This avoids the per-item static-data race where only the last write persists.

const items = $input.all();
const staticData = $getWorkflowStaticData('global');
staticData.announcedVendors = staticData.announcedVendors || {};

let vendors = [];
for (const item of items) {
  const j = item.json;
  if (Array.isArray(j)) {
    vendors.push(...j);
  } else if (Array.isArray(j.data)) {
    vendors.push(...j.data);
  } else if (j.id) {
    vendors.push(j);
  }
}

const now = Date.now();
const fresh = [];

for (const vendor of vendors) {
  const vendorId = String(vendor.id);
  if (staticData.announcedVendors[vendorId]) {
    continue;
  }
  staticData.announcedVendors[vendorId] = now;

  // Build a display-safe store reference for Slack.
  // If store_url exists, render as a Slack link "<url|name>".
  // Otherwise just the plain store name (Slack would render "<|name>" as broken).
  const storeName = vendor.store_name ?? `Vendor #${vendor.id}`;
  const storeUrl = vendor.store_url ?? '';
  const storeDisplay = storeUrl ? `<${storeUrl}|${storeName}>` : storeName;

  fresh.push({
    json: {
      vendor_id: vendor.id,
      store_name: storeName,
      store_display: storeDisplay,
      first_name: vendor.first_name ?? '',
      last_name: vendor.last_name ?? '',
      email: vendor.email ?? '',
      phone: vendor.phone ?? '',
      store_url: storeUrl,
      registered: vendor.registered ?? '',
      address: [
        vendor.address?.street_1,
        vendor.address?.city,
        vendor.address?.state,
        vendor.address?.country,
      ].filter(Boolean).join(', ') || 'Not provided',
      social: Object.entries(vendor.social ?? {})
        .filter(([_, url]) => url)
        .map(([k, url]) => `<${url}|${k}>`)
        .join(' · ') || 'None',
    }
  });
}

return fresh;

// Clear dedupe entry so if status flips back to inactive in the future, we re-announce.
const vendorId = String($('Approve clicked').item.json.query.id);
const staticData = $getWorkflowStaticData('global');
if (staticData.announcedVendors) {
  delete staticData.announcedVendors[vendorId];
}
return [{ json: $input.item.json }];

// Clear dedupe so if admin later reactivates, the workflow can re-announce.
const vendorId = String($('Reject clicked').item.json.query.id);
const staticData = $getWorkflowStaticData('global');
if (staticData.announcedVendors) {
  delete staticData.announcedVendors[vendorId];
}
return [{ json: $input.item.json }];

